INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-f7485f85-moex-00281', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司與客戶在X1年2月1日簽訂銷售合約，約定X2年2月1日前以每單位售價$100交付100 單位甲公司所生產之產品（單位成本為$90），若延遲交貨，則每單位售價$50。簽約時甲公司有能 力及意圖及時交付100單位產品，然而在X1年12月31日，甲公司僅交付80單位產品，且由於 產能限制，預期於X2年2月1日前僅能再生產並交付10單位產品，其餘10單位須至X2年3月 才能完成生產。關於此合約於X1年12月31日之會計處理，下列敘述何者正確？', '["若甲公司預期將延遲交付剩餘之10單位產品，由於整體合約仍可獲利$500，故X1年底不應認 列負債準備", "若甲公司預期將延遲交付剩餘之10單位產品，由於將及時交貨的10單位產品仍可獲利，僅延 遲交付的10單位產品每單位損失$40，故X1年底應認列負債準備$400", "若甲公司預期將延遲交付剩餘之10單位產品，由於尚未交貨之20單位產品預期可獲經濟效益 $1,500，不可避免成本$1,800，故X1年底應認列負債準備$300", "若甲公司預期將以每單位$95向同業調貨10單位以準時交付20單位產品予客戶，X1年底仍應 認列負債準備$50"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00282', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '關於財務報表之表達，下列敘述何者正確？', '["資產與負債必須按流動與非流動加以區分", "國際財務報導準則所規定之特定揭露必須提供", "按流動性順序表達資產時，必須以流動性遞減之順序表達", "同一資產中採用不同衡量基礎者，必須以個別單行項目表達"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00283', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司於X1年初購入丙設備，估計耐用年限為5年，估計殘值為$100,000，後續衡量採成本模式 並按年數合計法計提折舊。甲公司於 X2 年初以該設備和乙公司交換另一丁設備，換入之丁設備 公允價值為$1,500,000，並支付現金$200,000。甲公司對丁設備後續衡量仍採成本模式並按年數合 計法計提折舊，估計剩餘耐用年限為4年，估計殘值為$300,000，X2年度折舊為$480,000。已知 若甲公司對丙設備之折舊方法採雙倍餘額遞減法，則X1年丙設備之折舊為$400,000。下列有關前', '["丙設備原始成本為$1,000,000", "該項資產交換具商業實質", "X2年初應認列資產交換利益$500,000", "若X2年底甲公司評估丁設備可回收金額為$700,000， 則應認列資產減損損失$320,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00284', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司於X1年1月2日購買土地，購價為$4,500,000，並另支付$255,000將土地上的舊建築物拆 除重建，殘料售得$105,000。此外，並支付建築師設計費$480,000，整地費$150,000，道路鋪設費 $195,000，土地過戶費$75,000，建造工程費$2,550,000。試問土地成本為何？', '["$4,725,000", "$4,875,000", "$5,175,000", "$5,550,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00285', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '關於永續盤存制與定期盤存制下採用成本公式影響之比較，下列敘述何者正確？', '["採用先進先出成本公式且物價持續下跌時，永續盤存制下之銷貨成本可能高於定期盤存制下之 銷貨成本", "採用先進先出成本公式且物價持續下跌時，永續盤存制下之銷貨成本可能低於定期盤存制下之 銷貨成本", "採用加權平均成本公式且物價持續下跌時，永續盤存制下之銷貨成本可能高於定期盤存制下之 銷貨成本", "採用加權平均成本公式且物價持續下跌時，永續盤存制下之銷貨成本可能低於定期盤存制下之 銷貨成本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00286', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '假設甲公司X1年至X3年的淨利都是$250,000，若X1年底存貨低估$12,500，X2年底存貨高估 $12,500，X3年底存貨高估$25,000，假設前述存貨錯誤於X3年底前皆未被發現，試問甲公司X1 年至X3年正確的淨利為何？（不考慮所得稅影響數）', '["$250,000，$250,000，$250,000", "$262,500，$225,000，$237,500", "$237,500，$275,000，$262,500", "$225,000，$262,500，$275,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00287', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司X1年期末實地盤點庫存商品共有$600,000。會計師查核時發現下列狀況：①甲公司X1年 間將成本$85,000的商品運至丁公司，委託其代為銷售，丁公司墊付商品廣告費$1,000。按合約丁', '["承銷乙公司 商品尚未賣出，計有$18,000含於庫存貨品中", "X1年12月25日已運送之目的地交貨條件的銷 貨，商品成本$32,500，於X2年1月15日才運達", "X1年12月25日已運送之起運點交貨條件 的進貨$12,500，於X2年1月15日才收到。甲公司X1年期末正確存貨餘額應該為多少？", "$627,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00288', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司X1年底公司帳上銀行存款餘額為$152,460，銀行對帳單上銀行存款餘額為$197,700，銀行 調節表上之調節項目包括銀行代收款項$39,000，流通在外未兌現支票$49,800，銀行收取手續費 $4,200。此外，並發現公司開立之支票$40,500，於公司帳簿中被誤記為$45,900。假設差異原因僅 餘在途存款，試問甲公司X1年底在途存款應為：', '["$33,960", "$44,760", "$54,840", "$65,640"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00289', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司X1年底調整前試算表上之收入為$90,000，費用為$51,000，可能須調整之事項為：預收收 入已實現部分為$7,500，本期折舊$3,600，已賺得但尚未入帳之收益為$6,000，試問甲公司X1年 淨利為何？（不考慮所得稅）', '["$48,900", "$36,900", "$33,900", "$21,900"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00290', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '下列何者屬企業之會計政策選擇？①存貨成本公式採加權平均法或先進先出法  ②不動產廠房', '["農業產品之原始衡量採公允價值減出售成本或成本", "投資性不動產之後續衡量採成本模式或公允價值模式  ⑤生物資產之衡量採公允價值減出售 成本模式或成本模式  ⑥建造合約之收入認列採完工百分比法或成本回收法", "僅", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "d8aa68995e77", "answer_pdf_sha1": "c3fb6e90ebac", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL)
